@startuml
skinparam classAttributeIconSize 0
hide circle

class User {
    String name
    String email
}

class Shelf {
    String name
}

class Note {
    String title
    String body
}

class Article {
    String title
    String url
}

class Tag {
    String body
}

User --> "followes" User : 
User -down-> "creates" Shelf : creates
User --|> "likes" Shelf : likes
Shelf o-- "contains" Note : contains
Note *--> "attaches" Tag : attaches
Tag <--* "attaches" Shelf : attaches
Article *--> "attaches" Tag : attaches
User -> "finds" Article : finds
User <-right- "likes" Article : likes
User <|-left-"followes" Tag : followes
User -up-left-> "creates" Note : creates
User -u[hidden]-> "likes" Note : likes
@enduml
